public class StringReversal {
    public static String reverse(String input) {
        if (input == null) return null;
        char[] chars = input.toCharArray();
        int left = 0;
        int right = chars.length - 1;
        while (left < right) {
            char temp = chars[left];
            chars[left] = chars[right];
            chars[right] = temp;
            left++;
            right--;
        }
        return new String(chars);
    }

    public static void main(String[] args) {
        String original = "JavaMaster";
        String reversed = reverse(original);
        System.out.println("Original: " + original);
        System.out.println("Reversed: " + reversed);
    }
}

import java.util.HashMap;
import java.util.Arrays;

public class TwoSum {
    public static int[] findTwoSum(int[] nums, int target) {
        HashMap<Integer, Integer> map = new HashMap<>();
        for (int i = 0; i < nums.length; i++) {
            int complement = target - nums[i];
            if (map.containsKey(complement)) {
                return new int[] { map.get(complement), i };
            }
            map.put(nums[i], i);
        }
        return new int[] {}; // No solution found
    }

    public static void main(String[] args) {
        int[] numbers = {2, 7, 11, 15};
        int target = 9;
        int[] result = findTwoSum(numbers, target);
        System.out.println("Indices: " + Arrays.toString(result));
    }
}

import java.util.Arrays;

public class Fibonacci {
    private static int[] memo;

    public static int getFibonacci(int n) {
        memo = new int[n + 1];
        Arrays.fill(memo, -1);
        return fib(n);
    }

    private static int fib(int n) {
        if (n <= 1) return n;
        if (memo[n] != -1) return memo[n];

        memo[n] = fib(n - 1) + fib(n - 2);
        return memo[n];
    }

    public static void main(String[] args) {
        int n = 10;
        System.out.println("Fibonacci of " + n + " is: " + getFibonacci(n));
    }
}

public class BinarySearch {
    public static int search(int[] arr, int target) {
        int low = 0;
        int high = arr.length - 1;
        while (low <= high) {
            int mid = low + (high - low) / 2;
            if (arr[mid] == target) {
                return mid;
            }
            if (arr[mid] < target) {
                low = mid + 1;
            } else {
                high = mid - 1;
            }
        }
        return -1; // Not found
    }

    public static void main(String[] args) {
        int[] sortedArray = {2, 5, 8, 12, 16, 23, 38, 56, 72};
        int target = 23;
        int index = search(sortedArray, target);
        System.out.println("Element " + target + " found at index: " + index);
    }
}

public class LinkedListCycle {
    static class Node {
        int data;
        Node next;
        Node(int val) {
            this.data = val;
            this.next = null;
        }
    }

    public static boolean hasCycle(Node head) {
        if (head == null) return false;
        Node slow = head;
        Node fast = head;
        while (fast != null && fast.next != null) {
            slow = slow.next;
            fast = fast.next.next;
            if (slow == fast) {
                return true; // Loop detected
            }
        }
        return false;
    }

    public static void main(String[] args) {
        Node head = new Node(1);
        head.next = new Node(2);
        Node loopNode = new Node(3);
        head.next.next = loopNode;
        loopNode.next = new Node(4);
        loopNode.next.next = loopNode; // Creates a cycle pointing back to node 3

        System.out.println("Has Cycle: " + hasCycle(head));
    }
}

public class NumberReversal {
    public static int reverse(int num) {
        int rev = 0;
        while (num > 0) {
            int rem = num % 10;
            rev = (rev * 10) + rem;
            num /= 10;
        }
        return rev;
    }

    public static void main(String[] args) {
        int number = 12345;
        int reversed = reverse(number);
        System.out.println("Original: " + number);
        System.out.println("Reversed: " + reversed);
    }
}

public class PalindromeNumber {
    public static boolean isPalindrome(int num) {
        int temp = num;
        int rev = 0;
        while (num > 0) {
            int rem = num % 10;
            rev = (rev * 10) + rem;
            num /= 10;
        }
        return temp == rev;
    }

    public static void main(String[] args) {
        int val = 121;
        System.out.println(val + " is Palindrome: " + isPalindrome(val));
    }
}

public class ArmstrongNumber {
    public static boolean isArmstrong(int num) {
        int temp = num;
        int sum = 0;
        while (num > 0) {
            int rem = num % 10;
            sum += (rem * rem * rem);
            num /= 10;
        }
        return temp == sum;
    }

    public static void main(String[] args) {
        int val = 153;
        System.out.println(val + " is Armstrong: " + isArmstrong(val));
    }
}

public class PrimeChecker {
    public static boolean isPrime(int num) {
        if (num <= 1) return false;
        for (int i = 2; i * i <= num; i++) {
            if (num % i == 0) {
                return false;
            }
        }
        return true;
    }

    public static void main(String[] args) {
        int val = 13;
        System.out.println(val + " is Prime: " + isPrime(val));
    }
}

public class SwapNumbers {
    public static void main(String[] args) {
        int a = 10;
        int b = 20;
        System.out.println("Before Swap - a: " + a + ", b: " + b);

        a = a + b; // a becomes 30
        b = a - b; // b becomes 10
        a = a - b; // a becomes 20

        System.out.println("After Swap - a: " + a + ", b: " + b);
    }
}

public class MaxInArray {
    public static int findMax(int[] arr) {
        int max = arr[0];
        for (int i = 1; i < arr.length; i++) {
            if (arr[i] > max) {
                max = arr[i];
            }
        }
        return max;
    }

    public static void main(String[] args) {
        int[] nums = {25, 945, 326, 8, 90};
        System.out.println("Maximum element: " + findMax(nums));
    }
}

public class MissingNumber {
    public static int findMissing(int[] arr, int n) {
        int expectedSum = n * (n + 1) / 2;
        int actualSum = 0;
        for (int num : arr) {
            actualSum += num;
        }
        return expectedSum - actualSum;
    }

    public static void main(String[] args) {
        int[] nums = {1, 2, 4, 5, 6}; // 3 is missing, N = 6
        System.out.println("Missing Number: " + findMissing(nums, 6));
    }
}

import java.util.Arrays;

public class ReverseArray {
    public static void reverse(int[] arr) {
        int start = 0;
        int end = arr.length - 1;
        while (start < end) {
            int temp = arr[start];
            arr[start] = arr[end];
            arr[end] = temp;
            start++;
            end--;
        }
    }

    public static void main(String[] args) {
        int[] nums = {10, 20, 30, 40, 50};
        reverse(nums);
        System.out.println("Reversed: " + Arrays.toString(nums));
    }
}

import java.util.Arrays;

public class BubbleSort {
    public static void sort(int[] arr) {
        int n = arr.length;
        for (int i = 0; i < n - 1; i++) {
            for (int j = 0; j < n - i - 1; j++) {
                if (arr[j] > arr[j + 1]) {
                    int temp = arr[j];
                    arr[j] = arr[j + 1];
                    arr[j + 1] = temp;
                }
            }
        }
    }

    public static void main(String[] args) {
        int[] nums = {22, 5, 6, 88, 9};
        sort(nums);
        System.out.println("Sorted: " + Arrays.toString(nums));
    }
}
